import React, { useState, useEffect } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const clientSecret = 'YOUR_CLIENT_SECRET';
const redirectUri = 'https://your-app.com/callback';
const authorizationEndpoint = 'https://authorization-server.com/oauth/authorize';
const tokenEndpoint = 'https://authorization-server.com/oauth/token';
const scope = 'read write';

function App() {
  const [accessToken, setAccessToken] = useState(localStorage.getItem('accessToken'));
  const [authCode, setAuthCode] = useState('');

  useEffect(() => {
    if (accessToken) {
      // Use accessToken to make API requests
    }
  }, [accessToken]);

  const handleLogin = () => {
    window.location.href = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${scope}`;
  };

  const handleCallback = (event) => {
    event.preventDefault();
    const urlParams = new URLSearchParams(window.location.search);
    setAuthCode(urlParams.get('code'));
  };

  const exchangeCodeForToken = async () => {
    try {
      const response = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: authCode,
          redirect_uri: redirectUri,
          client_id: clientId,
          client_secret: clientSecret,
        }),
      });

      const data = await response.json();
      setAccessToken(data.access_token);
      localStorage.setItem('accessToken', data.access_token);
    } catch (error) {
      console.error('Error exchanging code for token:', error);
    }
  };

  return (
    <div>
      {accessToken ? (
        <h1>Logged In</h1>
      ) : (
        <>
          <button onClick={handleLogin}>Login with OAuth</button>
          {authCode && (
            <form onSubmit={handleCallback}>
              <input type="hidden" value={authCode} />
              <button type="submit">Exchange Code for Token</button>
            </form>
          )}
        </>
      )}
    </div>
  );
}

export default App;